function [imgLst,shtNmb,bgNam,goFlag] = fImgLstV02(inpDir,fName)%% Function to get a list of existing image and shot number%% [imgLst,shtNmb,bgNam] = fImgLstV02(inpDir,fName)%% inpDir: directory to look for images% fName: part of the name of the images,%% imgLst: list of the name of images% shtNmb: shotnumbers (1d array)% bgNam: img list for shot number<0 (bg)%% Kei Nakamura% Created on Friday, August 14th 2009.% ver.2: negative shot number for background%       Friday, April 8th 2011.%%goFlag = 1;sensysBG = 0;   % sensys bg flagimgLst = dir([inpDir,fName]);  % image listif numel(imgLst)==0 % there is no image    goFlag = 0;    shtNmb = 0;    bgNam = 0;else    for ii=1:numel(imgLst); % list loop        name = imgLst(ii).name;        prt = fGetPartStrV03(name,'_','*');        prt = prt(4:end);        shtNmbS = fGetPartStrV03(prt,'_','.');        if shtNmbS(1) ~= 'B';            shtNmb(ii) = str2num(shtNmbS);        else            sensysBG = 1;   % sensys BG            bgNam = imgLst(ii);    % sensys BG name            shtNmb(ii) = -ii;        end            end        if sensysBG==0  % no sensys background        bgNam = imgLst(shtNmb(:)<0);        if min(shtNmb(:)>0) % if no back ground            goFlag = 0;        end    end        imgLst = imgLst(shtNmb(:)>0);    shtNmb = shtNmb(shtNmb(:)>0);     end
